"""Part 2: Rice (25) + Breakfast (25) = 50 recipes, SL_0236-SL_0285"""
import json

def m(i,n,c,d,p,ck,s,r,sp,ings,mt,t,cn):
    return {"id":f"SL_{i:04d}","names":{"english":n},"category":c,"difficulty":d,"prep_time_mins":p,"cook_time_mins":ck,"servings":s,"region":r,"spice_level":sp,"is_authentic":True,"ingredients":[{"name":x,"amount":y} for x,y in ings],"method":mt,"tips":t,"cultural_note":cn}

R=[]
# RICE (25) SL_0236-0260
R.append(m(236,"Yellow Rice (Kaha Bath)","rice","easy",10,25,6,"Island-wide",1,[("basmati rice","2 cups"),("coconut milk","2 cups"),("turmeric","1 tsp"),("pandan leaves","2"),("cardamom","3 pods"),("cloves","3"),("cinnamon stick","1"),("cashew nuts","2 tbsp"),("raisins","2 tbsp"),("salt","1 tsp")],"1. Wash rice, drain\n2. Heat oil, fry cashews and raisins, set aside\n3. Add whole spices, saute 1 min\n4. Add rice, turmeric, salt, stir\n5. Add coconut milk and pandan, bring to boil\n6. Cover, cook on low 20 mins, fluff with fork, garnish with cashews and raisins","Use good quality basmati for fluffy separate grains.","Yellow rice is the centerpiece of Sri Lankan celebrations - weddings, New Year, and religious ceremonies."))
R.append(m(237,"Ghee Rice","rice","medium",15,30,6,"Eastern Province",1,[("basmati rice","2 cups"),("ghee","3 tbsp"),("onion","2"),("cardamom","4 pods"),("cloves","4"),("cinnamon stick","1"),("bay leaves","2"),("cashew nuts","2 tbsp"),("raisins","2 tbsp"),("chicken stock","3 cups"),("salt","1 tsp")],"1. Wash and soak rice 30 mins\n2. Heat ghee, fry cashews and raisins, remove\n3. Saute onions with whole spices until golden\n4. Add drained rice, stir 2 mins\n5. Add stock, salt, bring to boil\n6. Cover tight, cook low 20 mins, garnish","Use real ghee, not butter, for authentic aroma.","Ghee rice is a festive Muslim dish served at weddings and Eid celebrations in Eastern Sri Lanka."))
R.append(m(238,"Chicken Biriyani","rice","hard",30,60,6,"Eastern Province",3,[("basmati rice","3 cups"),("chicken","1 kg"),("onion","3 large"),("yogurt","1 cup"),("biriyani masala","3 tbsp"),("turmeric","1/2 tsp"),("saffron","pinch"),("mint leaves","1 cup"),("coriander leaves","1 cup"),("ghee","4 tbsp"),("garlic","8 cloves"),("ginger","2 inch"),("green chili","6"),("cashews","3 tbsp"),("raisins","3 tbsp")],"1. Marinate chicken in yogurt, masala, garlic, ginger for 2 hours\n2. Parboil rice with whole spices until 70% cooked\n3. Deep fry onions until crispy\n4. In pot layer: chicken, rice, fried onions, mint, coriander\n5. Add saffron milk, ghee, seal with foil\n6. Cook on dum (very low heat) 30 mins","Don't open the lid during dum cooking - the steam does the magic.","Sri Lankan biriyani, especially from Akkaraipattu and Kalmunai, has its own unique style distinct from Indian versions."))
R.append(m(239,"Lamprais","rice","hard",60,120,8,"Western Province",2,[("basmati rice","3 cups"),("beef curry","500g"),("chicken curry","500g"),("frikkadels (meatballs)","12"),("eggplant moju","1 cup"),("blachan (prawn paste sambol)","1/2 cup"),("hard-boiled eggs","4"),("banana leaves","8 pieces"),("mixed meat stock","4 cups"),("ghee","2 tbsp"),("cardamom","4"),("cloves","4")],"1. Cook rice in mixed meat stock with spices\n2. Prepare all components: beef curry, chicken curry, frikkadels, moju, blachan\n3. Soften banana leaves over flame\n4. Place rice on banana leaf, add portions of each component\n5. Add half a boiled egg\n6. Wrap tightly, bake in oven at 180C for 20 mins","Each component must be prepared separately for authentic lamprais.","Lamprais is Sri Lanka's most famous Dutch Burgher dish, derived from the Dutch 'lomprijst'. It is a complete meal wrapped in banana leaf."))
R.append(m(240,"Milk Rice (Kiribath)","rice","easy",5,25,6,"Island-wide",0,[("short grain rice","2 cups"),("coconut milk","3 cups"),("salt","1 tsp"),("water","1 cup")],"1. Wash rice thoroughly\n2. Cook rice with water until half done\n3. Add thick coconut milk and salt\n4. Stir gently and cook until milk is absorbed\n5. Press into flat tray, smooth the surface\n6. Cut into diamond shapes when slightly cool","Use full-fat thick coconut milk for creamy results.","Kiribath is the first food cooked in a new year and for every auspicious occasion. It symbolizes prosperity and new beginnings in Sri Lankan culture."))
R.append(m(241,"Coconut Rice","rice","easy",10,25,4,"Southern Province",1,[("rice","2 cups"),("desiccated coconut","1/2 cup"),("coconut milk","1 cup"),("water","1 cup"),("pandan leaves","2"),("curry leaves","1 sprig"),("salt","1 tsp"),("cashews","2 tbsp")],"1. Toast desiccated coconut in dry pan until golden\n2. Wash rice, add to pot with coconut milk and water\n3. Add pandan, curry leaves, salt\n4. Cook until done\n5. Fold in toasted coconut\n6. Garnish with fried cashews","Toast coconut on low heat, stirring constantly to avoid burning.","Coconut rice is a fragrant Southern Sri Lankan specialty that highlights the island's abundance of coconut."))
R.append(m(242,"Vegetable Fried Rice","rice","easy",15,15,4,"Island-wide",2,[("cooked rice","3 cups"),("carrot","1"),("leeks","1"),("capsicum","1"),("cabbage","1 cup"),("onion","1"),("egg","2"),("soy sauce","2 tbsp"),("garlic","4 cloves"),("green chili","3"),("salt","to taste"),("oil","3 tbsp")],"1. Use day-old cold rice for best results\n2. Heat oil on high, scramble eggs, remove\n3. Stir-fry garlic, onions, green chilies\n4. Add all vegetables, cook 3 mins on high\n5. Add rice, soy sauce, toss vigorously\n6. Add eggs back, mix well","Day-old refrigerated rice makes the best fried rice - less sticky.","Chinese-style fried rice has been adopted as a Sri Lankan staple, served at every restaurant and party."))
R.append(m(243,"Chicken Fried Rice","rice","easy",15,20,4,"Island-wide",2,[("cooked rice","3 cups"),("chicken breast","300g"),("carrot","1"),("leeks","1"),("capsicum","1"),("egg","2"),("soy sauce","2 tbsp"),("oyster sauce","1 tbsp"),("garlic","4 cloves"),("ginger","1 inch"),("oil","3 tbsp")],"1. Dice chicken, season with salt and pepper\n2. Stir-fry chicken on high heat, set aside\n3. Scramble eggs, set aside\n4. Stir-fry all vegetables with garlic and ginger\n5. Add cold rice, soy sauce, oyster sauce\n6. Return chicken and egg, toss on high heat","Cut chicken into small uniform pieces for even cooking.","Chicken fried rice is the most popular single dish ordered at Sri Lankan Chinese restaurants."))
R.append(m(244,"Egg Fried Rice","rice","easy",10,10,2,"Island-wide",1,[("cooked rice","2 cups"),("eggs","3"),("onion","1"),("garlic","3 cloves"),("soy sauce","1 tbsp"),("green onions","2 stalks"),("salt","to taste"),("oil","2 tbsp"),("white pepper","1/4 tsp")],"1. Beat eggs lightly with salt\n2. Heat oil on high, pour in eggs, scramble quickly\n3. Add garlic and onions, stir-fry 1 min\n4. Add cold rice, break up lumps\n5. Add soy sauce, white pepper\n6. Garnish with green onions","High heat and quick movements are key to good fried rice.","Egg fried rice is Sri Lanka's most affordable fried rice option, popular with students."))
R.append(m(245,"Seafood Fried Rice","rice","medium",20,15,4,"Western Province",2,[("cooked rice","3 cups"),("prawns","200g"),("squid","150g"),("crab sticks","100g"),("carrot","1"),("leeks","1"),("capsicum","1"),("egg","2"),("soy sauce","2 tbsp"),("fish sauce","1 tbsp"),("garlic","5 cloves"),("oil","3 tbsp")],"1. Clean prawns and squid, slice squid into rings\n2. Stir-fry seafood on high heat 2 mins, remove\n3. Scramble eggs, remove\n4. Stir-fry vegetables with garlic\n5. Add rice, soy sauce, fish sauce\n6. Return seafood and eggs, toss well","Cook seafood briefly on very high heat.","Seafood fried rice is a premium dish at Sri Lankan restaurants, often served at parties."))
R.append(m(246,"Nasi Goreng","rice","medium",15,15,4,"Western Province",3,[("cooked rice","3 cups"),("chicken","200g"),("prawns","150g"),("onion","2"),("garlic","4 cloves"),("chili paste","2 tbsp"),("soy sauce","2 tbsp"),("sweet soy sauce","1 tbsp"),("egg","2"),("cucumber","1"),("fried shallots","2 tbsp")],"1. Dice chicken, stir-fry with prawns, set aside\n2. Scramble eggs, set aside\n3. Saute onions, garlic, chili paste\n4. Add rice, soy sauces, toss on high heat\n5. Return chicken, prawns, eggs\n6. Serve topped with fried egg, cucumber, shallots","Use kecap manis (sweet soy) for authentic flavor.","Nasi Goreng reflects the Malay cultural influence on Sri Lankan cuisine, particularly in Colombo."))
R.append(m(247,"Tomato Rice","rice","easy",10,25,4,"Island-wide",2,[("rice","2 cups"),("tomato","4 large"),("onion","1"),("garlic","3 cloves"),("chili powder","1/2 tsp"),("turmeric","1/4 tsp"),("cinnamon stick","1"),("curry leaves","1 sprig"),("oil","2 tbsp"),("salt","1 tsp"),("water","2.5 cups")],"1. Blend 2 tomatoes, dice remaining 2\n2. Heat oil, saute onions, garlic, cinnamon\n3. Add diced tomatoes, cook 3 mins\n4. Add rice, blended tomato, water, spices\n5. Bring to boil, cover, cook on low 20 mins\n6. Fluff with fork","Use ripe red tomatoes for best color and flavor.","Tomato rice is a quick one-pot meal popular for lunch boxes and picnics."))
R.append(m(248,"String Hopper Pilau","rice","medium",20,30,4,"Northern Province",2,[("string hoppers","20"),("onion","2"),("curry powder","1 tbsp"),("turmeric","1/4 tsp"),("cardamom","3 pods"),("cloves","3"),("cashew nuts","2 tbsp"),("green peas","1/2 cup"),("eggs","2"),("curry leaves","1 sprig"),("oil","3 tbsp")],"1. Break string hoppers into small pieces\n2. Heat oil, fry cashews, set aside\n3. Saute onions with whole spices\n4. Add curry powder, turmeric, peas\n5. Add string hopper pieces, toss gently\n6. Scramble eggs into mixture, garnish with cashews","Use slightly dry string hoppers for better texture.","String hopper pilau is a creative Jaffna innovation that repurposes leftover string hoppers into a flavorful one-dish meal."))
R.append(m(249,"Malay Rice (Buriyani)","rice","hard",30,50,6,"Western Province",3,[("basmati rice","3 cups"),("mutton","500g"),("onion","3"),("yogurt","1/2 cup"),("curry powder","2 tbsp"),("turmeric","1/2 tsp"),("saffron","pinch"),("ghee","3 tbsp"),("mint","1/2 cup"),("rose water","1 tbsp"),("garlic","6 cloves"),("ginger","2 inch"),("cardamom","4"),("cashews","3 tbsp")],"1. Marinate mutton in yogurt and spices\n2. Cook marinated mutton until tender\n3. Parboil rice with whole spices\n4. Deep fry onions until crispy\n5. Layer meat, rice, onions, mint in pot, drizzle saffron milk and rose water\n6. Seal and cook on very low heat 25 mins","The rose water and saffron are what distinguish Malay buriyani.","Sri Lankan Malay buriyani is a heritage recipe brought by Malay soldiers during Dutch colonial times."))
R.append(m(250,"Tamarind Rice","rice","easy",10,25,4,"Northern Province",2,[("rice","2 cups"),("tamarind paste","2 tbsp"),("onion","1"),("peanuts","2 tbsp"),("mustard seeds","1 tsp"),("curry leaves","1 sprig"),("dried red chili","3"),("turmeric","1/4 tsp"),("sesame oil","2 tbsp"),("salt","1 tsp"),("water","2.5 cups")],"1. Cook rice and cool\n2. Heat sesame oil, add mustard seeds, dried chilies\n3. Add peanuts, curry leaves, saute\n4. Add tamarind paste, turmeric, salt, cook 2 mins\n5. Add cooled rice, mix thoroughly\n6. Serve at room temperature","Spreading cooked rice on a tray to cool prevents it from becoming mushy.","Tamarind rice is a Tamil dish popular in Northern Sri Lanka, often prepared for temple offerings."))
R.append(m(251,"Prawn Biriyani","rice","hard",30,50,6,"Eastern Province",3,[("basmati rice","3 cups"),("prawns","500g"),("onion","3"),("yogurt","1/2 cup"),("biriyani masala","2 tbsp"),("turmeric","1/2 tsp"),("saffron","pinch"),("ghee","3 tbsp"),("mint","1/2 cup"),("garlic","6 cloves"),("ginger","1.5 inch"),("green chili","4"),("cashews","2 tbsp"),("lime juice","1 tbsp")],"1. Marinate prawns in yogurt, masala, lime juice\n2. Parboil rice with whole spices\n3. Deep fry onions, set aside\n4. Cook marinated prawns 5 mins\n5. Layer rice, prawns, onions, mint in pot\n6. Seal, cook on dum 20 mins","Do not overcook prawns before layering.","Prawn biriyani from Batticaloa is considered one of the finest rice dishes in Sri Lanka."))
R.append(m(252,"Coconut Milk Rice (Kiri Bath Variation)","rice","easy",5,30,4,"Island-wide",0,[("samba rice","2 cups"),("thick coconut milk","2 cups"),("water","1 cup"),("salt","1 tsp"),("pandan leaves","2")],"1. Wash rice thoroughly\n2. Add water and pandan leaves, cook until water is absorbed\n3. Pour in thick coconut milk\n4. Stir gently on low heat\n5. Cook until all milk is absorbed and rice is creamy\n6. Press flat, cut into pieces","Samba rice gives a stickier, more traditional texture than basmati.","This variation uses samba rice for a more rustic, village-style milk rice."))
R.append(m(253,"Mushroom Rice","rice","easy",15,25,4,"Central Province",1,[("basmati rice","2 cups"),("mushrooms","200g"),("onion","1"),("garlic","3 cloves"),("butter","2 tbsp"),("soy sauce","1 tbsp"),("black pepper","1/2 tsp"),("thyme","1/2 tsp"),("chicken stock","2.5 cups"),("salt","to taste")],"1. Slice mushrooms, saute in butter until brown\n2. Saute onions and garlic\n3. Add rice, stir 2 minutes\n4. Add stock, soy sauce, pepper, thyme\n5. Bring to boil, cover, cook low 20 mins\n6. Fluff and fold in mushrooms","Cook mushrooms separately for best caramelization.","Mushroom rice is a modern Sri Lankan dish popular in hill country restaurants."))
R.append(m(254,"Fish Biriyani","rice","hard",30,50,6,"Eastern Province",3,[("basmati rice","3 cups"),("seer fish","500g"),("onion","3"),("yogurt","1/2 cup"),("biriyani masala","2 tbsp"),("turmeric","1/2 tsp"),("saffron","pinch"),("ghee","3 tbsp"),("mint","1/2 cup"),("coriander","1/2 cup"),("garlic","6 cloves"),("ginger","1.5 inch"),("tomato","2"),("lime","1")],"1. Marinate fish in yogurt, masala, lime juice 30 mins\n2. Parboil rice, drain\n3. Fry onions crispy, set aside half\n4. Cook marinated fish with tomatoes 10 mins\n5. Layer rice, fish curry, onions, herbs\n6. Seal with foil, dum cook 20 mins","Use firm fish fillets that won't break during cooking.","Fish biriyani is a specialty of coastal Eastern Province towns."))
R.append(m(255,"Lunu Miris Rice","rice","easy",10,25,4,"Southern Province",3,[("cooked rice","3 cups"),("lunu miris","4 tbsp"),("onion","1"),("Maldive fish","2 tbsp"),("curry leaves","1 sprig"),("oil","2 tbsp"),("salt","to taste")],"1. Prepare lunu miris (chili, onion, lime, Maldive fish, salt)\n2. Heat oil, saute onions and curry leaves\n3. Add Maldive fish\n4. Add cooked rice, toss on high heat\n5. Mix in lunu miris thoroughly\n6. Serve hot","Use freshly ground lunu miris for best flavor.","A quick, fiery rice dish inspired by the flavors of Southern Sri Lanka."))
R.append(m(256,"Cinnamon Rice","rice","easy",10,25,4,"Central Province",1,[("basmati rice","2 cups"),("cinnamon sticks","3"),("cloves","3"),("cardamom","3"),("bay leaf","1"),("ghee","1 tbsp"),("cashews","2 tbsp"),("raisins","2 tbsp"),("salt","1 tsp"),("water","2.5 cups")],"1. Wash rice, soak 15 mins\n2. Heat ghee, fry cashews and raisins\n3. Add whole spices, saute 1 min\n4. Add rice, stir gently\n5. Add water, salt, bring to boil\n6. Cover, cook low 20 mins","Use Ceylon cinnamon for the most authentic sweet aroma.","Sri Lanka is the world's largest producer of true cinnamon. This rice celebrates that heritage."))
R.append(m(257,"Red Rice and Curry (Rathu Kekulu Bath)","rice","easy",5,35,4,"Sabaragamuwa",1,[("red rice (kekulu)","2 cups"),("water","3 cups"),("salt","1 tsp")],"1. Wash red rice well\n2. Add water and salt\n3. Bring to a boil\n4. Reduce to low heat, cover tightly\n5. Cook 30-35 minutes until tender\n6. Fluff with fork and serve with curries","Red rice takes longer to cook than white rice - be patient.","Red rice is the traditional staple grain of Sri Lanka, considered more nutritious than polished white rice. It has a nutty flavor and chewy texture."))
R.append(m(258,"Kottu Roti","rice","medium",15,15,4,"Island-wide",3,[("godamba roti","4"),("chicken","200g"),("cabbage","1 cup"),("carrot","1"),("leeks","1"),("egg","2"),("curry sauce","1/2 cup"),("soy sauce","1 tbsp"),("chili flakes","1 tsp"),("garlic","3 cloves"),("oil","3 tbsp")],"1. Tear or chop roti into small pieces\n2. Stir-fry chicken until cooked, set aside\n3. Scramble eggs, set aside\n4. Stir-fry vegetables on high heat\n5. Add roti pieces, curry sauce, soy sauce, chili\n6. Toss vigorously with spatulas on hot griddle, add chicken and egg","The rhythmic chopping sound on the hot griddle is signature of authentic kottu.","Kottu roti is Sri Lanka's most iconic street food. The rhythmic clanging of metal spatulas on the griddle can be heard from hotels across the island every evening."))
R.append(m(259,"Pittu Rice","rice","easy",15,20,4,"Island-wide",1,[("rice flour","2 cups"),("grated coconut","1 cup"),("salt","1 tsp"),("water","as needed")],"1. Mix rice flour with salt\n2. Sprinkle water gradually, mix until flour forms crumbles\n3. Layer flour and coconut alternately in pittu mold\n4. Steam for 10-15 minutes\n5. Push out of mold\n6. Serve with coconut milk curry or fish curry","The flour should feel like damp sand - not wet, not dry.","Pittu is unique to Sri Lanka and parts of South India. This cylindrical steamed rice dish is traditionally made using a bamboo mold."))
R.append(m(260,"Elawalu Lunu Bath (Vegetable Mixed Rice)","rice","easy",15,25,4,"Central Province",1,[("cooked rice","3 cups"),("carrot","1"),("green beans","1 cup"),("pumpkin","1 cup"),("leeks","1"),("coconut milk","1/2 cup"),("curry powder","1 tbsp"),("turmeric","1/4 tsp"),("mustard seeds","1/2 tsp"),("curry leaves","1 sprig"),("Maldive fish","1 tbsp"),("oil","2 tbsp")],"1. Dice all vegetables small\n2. Heat oil, add mustard seeds and curry leaves\n3. Saute vegetables with spices and Maldive fish\n4. Add coconut milk, cook until vegetables are tender\n5. Mix in cooked rice, toss gently\n6. Season and serve","Cut vegetables into very small dice so they blend with the rice.","This mixed rice is a one-pot meal common in Central Province households."))

# BREAKFAST (25) SL_0261-0285
R.append(m(261,"Plain Hoppers (Appa)","breakfast","medium",120,20,4,"Island-wide",0,[("rice flour","2 cups"),("coconut milk","1 cup"),("water","1/2 cup"),("yeast","1 tsp"),("sugar","1 tsp"),("salt","1/2 tsp"),("coconut cream","2 tbsp")],"1. Dissolve yeast and sugar in warm water, let froth\n2. Mix rice flour, salt, coconut milk, yeast mixture\n3. Add coconut cream, mix to thin batter\n4. Ferment 6-8 hours or overnight\n5. Heat hopper pan, add ladle of batter, swirl to coat\n6. Cover and cook 2-3 mins until edges are crispy and center is soft","Overnight fermentation gives the best flavor and texture.","Hoppers are Sri Lanka's most distinctive breakfast dish. The bowl-shaped rice pancake with crispy edges and soft center is found nowhere else in the world."))
R.append(m(262,"Egg Hoppers","breakfast","medium",5,5,4,"Island-wide",0,[("hopper batter","as per recipe"),("eggs","4"),("salt","pinch"),("pepper","pinch")],"1. Prepare hopper batter as for plain hoppers\n2. Heat hopper pan, add batter, swirl\n3. Crack an egg into center of hopper\n4. Sprinkle salt and pepper\n5. Cover and cook until egg white is set but yolk is runny\n6. Serve immediately with sambol","Keep the yolk runny for authentic egg hoppers.","Egg hoppers are the most popular Sri Lankan breakfast. The runny yolk mixed with spicy sambol is heavenly."))
R.append(m(263,"String Hoppers (Idiyappam)","breakfast","medium",30,15,6,"Island-wide",0,[("red rice flour","2 cups"),("hot water","2 cups"),("salt","1 tsp")],"1. Boil water with salt\n2. Add flour gradually, mix into dough\n3. Knead until smooth\n4. Fill string hopper press\n5. Press in circular motions onto bamboo mats\n6. Steam for 5-7 minutes","Knead the dough well - it should be soft and pliable, not crumbly.","String hoppers are a breakfast staple across Sri Lanka, traditionally served with kiri hodi and sambol."))
R.append(m(264,"Pittu","breakfast","easy",15,15,4,"Island-wide",0,[("red rice flour","2 cups"),("grated coconut","1 cup"),("salt","1 tsp"),("water","as needed")],"1. Combine flour and salt\n2. Add water slowly, rubbing between palms until texture is like wet sand\n3. Alternate layers of flour and coconut in pittu mold\n4. Attach mold to kettle of boiling water\n5. Steam 10-15 mins until steam comes through top\n6. Push out of mold, serve with curry","The flour mixture should crumble apart, never form a dough.","Pittu is a staple breakfast made in a cylindrical bamboo mold. Every household has their own pittu bamboo."))
R.append(m(265,"Roti (Godamba Roti)","breakfast","medium",30,15,4,"Island-wide",1,[("all-purpose flour","2 cups"),("salt","1/2 tsp"),("sugar","1 tsp"),("egg","1"),("water","1/2 cup"),("oil","for cooking")],"1. Mix flour, salt, sugar\n2. Add egg and water, knead into soft stretchy dough\n3. Oil the dough, rest 30 mins\n4. Pull small portions into thin sheets\n5. Fold into layers, place on hot griddle with oil\n6. Cook both sides until golden and flaky","The dough must be very thin and translucent when stretched.","Godamba roti is Sri Lanka's answer to the Indian paratha, brought by Malay Muslims."))
R.append(m(266,"Coconut Roti (Pol Roti)","breakfast","easy",10,15,6,"Island-wide",1,[("rice flour","1 cup"),("wheat flour","1 cup"),("grated coconut","1 cup"),("onion","1 small chopped"),("green chili","2 chopped"),("salt","1 tsp"),("water","as needed")],"1. Mix both flours, coconut, salt\n2. Add chopped onion and green chili\n3. Add water slowly to form stiff dough\n4. Divide into balls, flatten by hand into thick disks\n5. Cook on hot griddle without oil on both sides\n6. Press gently to check firmness, serve hot","Do not make the dough too wet - it should be firm and hold its shape.","Pol roti is the simplest, most common breakfast in rural Sri Lanka. It pairs perfectly with seeni sambol and a hot cup of Ceylon tea."))
R.append(m(267,"Milk Hopper","breakfast","medium",5,5,4,"Island-wide",0,[("hopper batter","as per recipe"),("coconut milk","1 cup"),("sugar","2 tbsp")],"1. Prepare hopper batter\n2. Make plain hoppers\n3. While still on pan, add sweetened coconut milk to center\n4. Cover briefly so milk sets slightly\n5. Remove carefully\n6. Serve as dessert hopper","The coconut milk should be thick and sweet.","Milk hoppers are the sweet version of Sri Lanka's iconic hopper, often served as dessert."))
R.append(m(268,"Ulundu Wade (Urad Dhal Fritter)","breakfast","medium",20,15,6,"Northern Province",2,[("urad dhal","1 cup"),("onion","1"),("green chili","3"),("curry leaves","10"),("salt","to taste"),("oil for frying","2 cups")],"1. Soak urad dhal 4 hours\n2. Grind into thick paste (do not add water)\n3. Mix in chopped onion, chili, curry leaves\n4. Shape into donuts with hole in center\n5. Deep fry in hot oil until golden brown\n6. Drain on paper and serve hot","The batter should be thick enough to hold shape. Test by dropping a bit in water - it should float.","Ulundu wade is a beloved Tamil breakfast snack, originating from Jaffna and now popular across the whole island."))
R.append(m(269,"Masala Dosa","breakfast","medium",30,15,4,"Northern Province",2,[("dosa batter","2 cups"),("potato","3"),("onion","1"),("green chili","2"),("mustard seeds","1/2 tsp"),("turmeric","1/4 tsp"),("curry leaves","1 sprig"),("oil","for cooking")],"1. Prepare dosa batter (fermented rice and urad dhal)\n2. Boil and mash potatoes\n3. Temper mustard seeds, saute onions, chilies, curry leaves\n4. Mix with mashed potato and turmeric\n5. Spread thin layer of batter on hot griddle, cook until crispy\n6. Place potato filling, fold in half","The batter must be fermented overnight for authentic taste.","Masala dosa is a popular Tamil breakfast in Northern Sri Lanka, with each household having its own family recipe."))
R.append(m(270,"Thosai (Dosa)","breakfast","medium",20,10,4,"Northern Province",1,[("rice","2 cups"),("urad dhal","1/2 cup"),("fenugreek seeds","1/4 tsp"),("salt","1 tsp"),("oil","for cooking")],"1. Soak rice and dhal separately for 6 hours\n2. Grind into smooth batter, mix together\n3. Add fenugreek and salt, ferment overnight\n4. Heat flat griddle, pour ladle of batter\n5. Spread in circular motion to thin crepe\n6. Cook until bottom is golden, serve with chutney","Fermentation in a warm place for 8-10 hours is essential.","Thosai is a staple Tamil breakfast that is crispy on the outside and soft inside."))
R.append(m(271,"Kola Kanda (Herbal Porridge)","breakfast","easy",15,30,4,"Island-wide",0,[("rice","1/2 cup"),("gotukola leaves","1 cup"),("hathawariya","1/4 cup"),("garlic","2 cloves"),("ginger","1/2 inch"),("coconut milk","1 cup"),("salt","to taste"),("jaggery","optional")],"1. Cook rice in excess water until very soft\n2. Wash and finely chop green leaves\n3. Blend leaves with a little water\n4. Add leaf puree to cooked rice porridge\n5. Add coconut milk, salt\n6. Simmer 10 minutes, serve with jaggery","Use a variety of greens for maximum health benefits.","Kola kanda is an ancient Ayurvedic breakfast that has seen a modern revival in Sri Lanka. It is believed to boost immunity and brain power."))
R.append(m(272,"Atta Roti (Whole Wheat Roti)","breakfast","easy",10,15,6,"Island-wide",1,[("whole wheat flour","2 cups"),("grated coconut","1/2 cup"),("onion","1 small"),("green chili","2"),("salt","1 tsp"),("water","as needed")],"1. Mix flour, coconut, chopped onion, chili, salt\n2. Add water to form stiff dough\n3. Divide into balls\n4. Flatten into rounds on a floured surface\n5. Cook on hot dry griddle on both sides\n6. Serve hot with curry","Use whole wheat atta flour for nutritional value.","Atta roti is the healthier alternative to white flour roti, popular with health-conscious Sri Lankans."))
R.append(m(273,"Kurakkan Roti (Finger Millet Roti)","breakfast","easy",10,15,6,"Uva Province",1,[("finger millet flour","1.5 cups"),("grated coconut","1 cup"),("onion","1 small"),("salt","1 tsp"),("water","as needed")],"1. Mix millet flour, coconut, chopped onion, salt\n2. Add water slowly to make firm dough\n3. Shape into flat rounds by hand\n4. Cook on hot griddle without oil\n5. Cook both sides until firm and slightly charred\n6. Serve with fish curry or sambol","Kurakkan dough is crumbly - use wet hands to shape.","Kurakkan (finger millet) roti is a traditional Uva Province breakfast, highly nutritious and gluten-free."))
R.append(m(274,"Idli (Steamed Rice Cakes)","breakfast","easy",15,15,6,"Northern Province",0,[("idli batter","3 cups"),("salt","1 tsp"),("oil","for greasing")],"1. Prepare fermented idli batter (rice and urad dhal)\n2. Grease idli molds with oil\n3. Pour batter into each mold\n4. Steam for 10-12 minutes\n5. Check with toothpick - it should come out clean\n6. Remove with wet spoon, serve with sambar and chutney","Proper fermentation makes idlis fluffy. Over-fermented batter makes sour idlis.","Idli is a quintessential Tamil breakfast, served with sambar and coconut chutney in homes across Jaffna."))
R.append(m(275,"Upma","breakfast","easy",10,15,4,"Northern Province",1,[("semolina","1 cup"),("onion","1"),("green chili","2"),("ginger","1/2 inch"),("mustard seeds","1/2 tsp"),("curry leaves","1 sprig"),("cashews","1 tbsp"),("water","2.5 cups"),("ghee","1 tbsp"),("salt","to taste")],"1. Dry roast semolina until fragrant, set aside\n2. Heat ghee, add mustard seeds, cashews\n3. Saute onions, ginger, green chili, curry leaves\n4. Add water and salt, bring to boil\n5. Slowly add roasted semolina while stirring\n6. Cover, cook on low 5 mins, fluff with fork","Stir continuously while adding semolina to prevent lumps.","Upma is a popular South Indian-Tamil breakfast, commonly prepared in Northern Sri Lankan households."))
R.append(m(276,"Puttu (Steamed Coconut-Rice Cylinders)","breakfast","easy",10,15,4,"Northern Province",0,[("rice flour","2 cups"),("grated coconut","1 cup"),("salt","1/2 tsp"),("water","as needed")],"1. Mix rice flour and salt\n2. Sprinkle water, rub between palms to form crumbles\n3. Fill puttu mold alternating flour and coconut layers\n4. Steam 10-12 minutes\n5. Push out of mold using wooden press\n6. Serve with banana and sugar or fish curry","The flour should be loose and crumbly, never packed tight.","Puttu is the Jaffna variation of pittu, typically served with sweetened coconut or spicy curries."))
R.append(m(277,"Kiribath with Lunu Miris","breakfast","easy",10,25,4,"Island-wide",3,[("rice","2 cups"),("coconut milk","3 cups"),("salt","1 tsp"),("red onion","2"),("dried chili","6"),("Maldive fish","2 tbsp"),("lime juice","2 tbsp"),("salt","to taste")],"1. Cook rice with coconut milk and salt into milk rice\n2. Press flat on a tray, cut into diamonds\n3. Grind chilies, onion, Maldive fish, salt in mortar\n4. Add lime juice to the chili paste\n5. Serve milk rice diamonds with lunu miris on the side\n6. Eat by scooping lunu miris onto each piece","The lunu miris should be freshly ground, not blended.","This is the iconic Sri Lankan breakfast for the first day of every month, and every New Year morning."))
R.append(m(278,"Pani Pol Roti (Sweet Coconut Stuffed Roti)","breakfast","medium",20,15,6,"Western Province",0,[("wheat flour","2 cups"),("grated coconut","1 cup"),("jaggery","1/2 cup"),("cardamom powder","1/4 tsp"),("salt","1/2 tsp"),("water","for dough"),("oil","for cooking")],"1. Mix flour, salt, water into soft dough, rest 15 mins\n2. Mix grated coconut, grated jaggery, cardamom for filling\n3. Roll dough into thin circles\n4. Place coconut filling in center, fold edges\n5. Flatten gently and cook on hot griddle with oil\n6. Cook both sides until golden","Grate the jaggery finely so it melts into the coconut.","Pani pol roti is a sweet breakfast treat that children especially love, filled with treacle-sweetened coconut."))
R.append(m(279,"Appam (Sweet Hopper Variation)","breakfast","medium",120,5,4,"Northern Province",0,[("rice flour","2 cups"),("coconut milk","1 cup"),("sugar","3 tbsp"),("yeast","1 tsp"),("water","1/2 cup"),("salt","pinch")],"1. Dissolve yeast and sugar in warm water\n2. Mix rice flour, coconut milk and yeast mixture\n3. Ferment 6-8 hours\n4. Heat hopper pan, pour batter and swirl\n5. Sprinkle sugar on center while cooking\n6. Cover and cook until edges are crispy","Ferment in a warm place for fluffiest results.","Appam is the Tamil version of hoppers, slightly sweeter and often paired with coconut milk."))
R.append(m(280,"Lavariya (Leaf Wrap Rice)","breakfast","easy",10,30,4,"Southern Province",0,[("rice","2 cups"),("grated coconut","1 cup"),("salt","1 tsp"),("kenda leaves (wild ginger)","8"),("water","2.5 cups")],"1. Wash rice, cook until almost done\n2. Mix in grated coconut and salt\n3. Place mixture on kenda leaves\n4. Wrap tightly into cylindrical parcels\n5. Steam wrapped parcels 15 minutes\n6. Unwrap and serve with curries","Use young tender leaves for wrapping.","Lavariya is a Southern Province specialty where rice is steamed in aromatic wild ginger leaves."))
R.append(m(281,"Thala Guli (Sesame Balls) with Appam","breakfast","easy",15,15,4,"Northern Province",0,[("sesame seeds","1 cup"),("jaggery","1/2 cup"),("grated coconut","1/2 cup"),("cardamom","1/4 tsp"),("rice flour","2 tbsp")],"1. Dry roast sesame seeds until golden\n2. Grind roasted sesame coarsely\n3. Melt jaggery with a splash of water\n4. Mix everything together\n5. Shape into small balls while warm\n6. Serve alongside appam or hoppers for breakfast","Roll quickly while mixture is warm - it hardens as it cools.","Thala guli is a nutritious Tamil sweet snack often served as a breakfast accompaniment."))
R.append(m(282,"Mung Kavum (Mung Bean Cake Breakfast)","breakfast","medium",30,20,6,"Western Province",0,[("mung bean flour","1 cup"),("rice flour","1 cup"),("coconut milk","1 cup"),("sugar","1/2 cup"),("salt","pinch"),("oil for frying","2 cups")],"1. Mix both flours\n2. Add coconut milk, sugar, salt to make thick batter\n3. Rest batter 15 minutes\n4. Heat oil to medium temperature\n5. Pour small ladlefuls into oil\n6. Fry on low heat until golden and cooked through","Low temperature frying ensures kavum cook through without burning.","Mung kavum are traditional fried cakes originally made for the Sinhala and Tamil New Year."))
R.append(m(283,"Banana Fritters (Kesel Muso)","breakfast","easy",5,10,4,"Island-wide",0,[("ripe bananas","4"),("rice flour","1/2 cup"),("sugar","2 tbsp"),("salt","pinch"),("turmeric","pinch"),("oil for frying","1 cup")],"1. Mash bananas thoroughly\n2. Mix in rice flour, sugar, salt, turmeric\n3. Form into small flat patties\n4. Heat oil to medium\n5. Fry patties until golden on both sides\n6. Drain and serve warm","Use overripe bananas for natural sweetness.","Banana fritters are the simplest Sri Lankan snack, an easy way to use up ripe bananas that might otherwise be wasted."))
R.append(m(284,"Congee (Rice Porridge)","breakfast","easy",5,30,4,"Island-wide",0,[("rice","1/2 cup"),("water","6 cups"),("coconut milk","1/2 cup"),("salt","to taste"),("ginger","1/2 inch"),("garlic","2 cloves")],"1. Wash rice and add to pot with water\n2. Add bruised ginger and garlic\n3. Bring to boil, then simmer 25-30 minutes\n4. Stir occasionally until thick and porridge-like\n5. Add coconut milk, salt\n6. Serve with dried fish or sambol","The longer you cook, the creamier it gets.","Rice congee is a comfort food breakfast especially during rainy days or when someone is feeling unwell."))
R.append(m(285,"Bread Rolls (Paan Rolls)","breakfast","medium",20,15,6,"Island-wide",2,[("bread slices","8"),("chicken or fish filling","2 cups"),("egg","2"),("breadcrumbs","1 cup"),("salt","to taste"),("oil for frying","2 cups")],"1. Remove bread crusts, flatten slices with rolling pin\n2. Place spoonful of curry filling on each slice\n3. Roll tightly, seal edges with egg wash\n4. Dip in beaten egg, then coat with breadcrumbs\n5. Deep fry until golden brown\n6. Drain and serve hot with tomato sauce","Squeeze the bread rolls firmly to seal so they don't open while frying.","Bread rolls are a classic Sri Lankan short eat, found in every bakery and commonly eaten for breakfast or as a snack."))

